// worker-public.js - Public facing worker (entry point)
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    try {
      if (path.startsWith('/api/users')) {
        return await env.USER_SERVICE.fetch(request);
      } else if (path.startsWith('/api/products')) {
        return await env.PRODUCT_SERVICE.fetch(request);
      } else if (path.startsWith('/api/orders')) {
        return await env.ORDER_SERVICE.fetch(request);
      } else if (path.startsWith('/api/analytics')) {
        return await env.ANALYTICS_SERVICE.fetch(request);
      } else if (path === '/health') {
        const health = await this.checkAllServices(env);
        return new Response(JSON.stringify(health), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else {
        return new Response(JSON.stringify({ error: 'Not Found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({ error: error.message }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  },

  async checkAllServices(env) {
    const services = ['USER_SERVICE', 'PRODUCT_SERVICE', 'ORDER_SERVICE', 'ANALYTICS_SERVICE'];
    const results = {};

    for (const service of services) {
      try {
        const healthCheck = await env[service].fetch(new Request('http://internal/health'));
        const data = await healthCheck.json();
        results[service] = data;
      } catch (error) {
        results[service] = { status: 'error', message: error.message };
      }
    }

    return {
      status: 'ok',
      services: results,
      timestamp: new Date().toISOString()
    };
  }
};

// worker-user-service.js - User Service
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/health') {
      return new Response(JSON.stringify({ status: 'healthy', service: 'user-service' }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/users' && request.method === 'GET') {
      const users = await this.getAllUsers(env);
      return new Response(JSON.stringify(users), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path.match(/^\/api\/users\/\d+$/) && request.method === 'GET') {
      const userId = path.split('/').pop();
      const user = await this.getUser(env, userId);
      
      if (!user) {
        return new Response(JSON.stringify({ error: 'User not found' }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      return new Response(JSON.stringify(user), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/users' && request.method === 'POST') {
      const userData = await request.json();
      const user = await this.createUser(env, userData);
      
      await env.ANALYTICS_SERVICE.fetch(new Request('http://internal/api/analytics/event', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'user_created',
          userId: user.id,
          timestamp: new Date().toISOString()
        })
      }));

      return new Response(JSON.stringify(user), {
        status: 201,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
      status: 405,
      headers: { 'Content-Type': 'application/json' }
    });
  },

  async getAllUsers(env) {
    const list = await env.USERS_KV.list();
    const users = [];
    
    for (const key of list.keys) {
      const user = await env.USERS_KV.get(key.name, 'json');
      if (user) users.push(user);
    }
    
    return users;
  },

  async getUser(env, userId) {
    return await env.USERS_KV.get(`user:${userId}`, 'json');
  },

  async createUser(env, userData) {
    const userId = Date.now().toString();
    const user = {
      id: userId,
      ...userData,
      createdAt: new Date().toISOString()
    };
    
    await env.USERS_KV.put(`user:${userId}`, JSON.stringify(user));
    return user;
  }
};

